    'Adamantine Armor': { name: 'Adamantine Armor', type: 'Armor', armorType: 'Medium', baseAC: 14, stealthDisadvantage: false, strengthReq: 0, weight: 40, cost: 'Uncommon (500 GP)', description: 'Reinforced with adamantine. Critical hits against you become normal hits.' },
