    // --- PUGILIST MAGIC ITEMS (Homebrew) ---
    'Bonebreakers': { name: 'Bonebreakers', type: 'Weapon', category: 'Simple', rangeType: 'Melee', damage: '1d4', damageType: 'Bludgeoning', properties: ['Light', 'Magical'], mastery: 'Push', weight: 1, cost: 'Legendary (200,000 GP)', description: 'Requires Attunement by a Pugilist. +3 Brass Knuckles. When you hit, you can maim the target: DC 19 CON or Broken Arm (Disadvantage on weapon attacks), Broken Leg (Speed halved), Broken Ribs (Disadvantage on STR/DEX checks/saves), or Broken Skull (Disadvantage on INT/WIS checks/saves). Maimed until Greater Restoration. Once per dawn.' },
